using HTX586CONTRACT.Domain.Contracts; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace HTX586CONTRACT.Infrastructure.Persistence.Configurations;
public sealed class ContractAttachmentConfiguration:IEntityTypeConfiguration<ContractAttachment>{public void Configure(EntityTypeBuilder<ContractAttachment>b){b.ToTable("ContractAttachments",t=>t.HasCheckConstraint("CK_ContractAttachments_FileSize","[FileSize] > 0"));b.HasKey(x=>x.Id);b.Property(x=>x.OriginalFileName).HasMaxLength(255).IsRequired();b.Property(x=>x.StoredFileName).HasMaxLength(255).IsRequired();b.Property(x=>x.FileUrl).HasMaxLength(500).IsRequired();b.Property(x=>x.ContentType).HasMaxLength(100).IsRequired();b.Property(x=>x.FileHash).HasMaxLength(128);b.HasOne(x=>x.Contract).WithMany(x=>x.Attachments).HasForeignKey(x=>x.ContractId).OnDelete(DeleteBehavior.Restrict);b.HasIndex(x=>new{x.ContractId,x.AttachmentType}).HasDatabaseName("IX_ContractAttachments_Contract_Type");b.HasQueryFilter(x=>!x.IsDeleted);}}
